export function makeSection(type: HomepageSectionType, patch: Partial<HomepageSection> = {}): HomepageSection { const stamp = now(); const base: HomepageSection = { id: id(), type, title: sectionTypeLabels[type], enabled: true, order: 0, content: defaultContent(type), styles: defaultStyles(type), animation: { style: 'fade-up', speed: 'normal', intensity: 'subtle', trigger: 'on-scroll', mobileBehavior: 'reduced' }, visibility: { desktop: true, tablet: true, mobile: true, public: true }, advanced: { seoLabel: sectionTypeLabels[type] }, createdAt: stamp, updatedAt: stamp }; return { ...base, ...patch, content: { ...base.content, ...(patch.content || {}) }, styles: { ...base.styles, ...(patch.styles || {}) }, animation: { ...base.animation, ...(patch.animation || {}) }, visibility: { ...base.visibility, ...(patch.visibility || {}) }, advanced: { ...base.advanced, ...(patch.advanced || {}) } }; }
export function normalizeGlobalStyles(styles?: Partial<HomepageGlobalStyles>): HomepageGlobalStyles { const designPatch = (styles?.design || {}) as Partial<GlobalDesignSettings>; const preset = (designPatch.themePreset || defaultGlobalDesign.themePreset) as GlobalDesignSettings['themePreset']; const presetDesign: GlobalDesignSettings = { themePreset: preset, ...designThemePresets[preset] }; return { ...defaultGlobalStyles, ...(styles || {}), animation: { ...defaultGlobalStyles.animation, ...(styles?.animation || {}) }, design: { ...presetDesign, ...designPatch, colors: { ...presetDesign.colors, ...(designPatch.colors || {}) }, header: { ...presetDesign.header, ...(designPatch.header || {}) }, background: { ...presetDesign.background, ...(designPatch.background || {}) }, buttons: { ...presetDesign.buttons, ...(designPatch.buttons || {}) }, cards: { ...presetDesign.cards, ...(designPatch.cards || {}) }, typography: { ...presetDesign.typography, ...(designPatch.typography || {}) } } }; }
